import{_ as h}from"./chunks/plugin-vue_export-helper.DlAUqK2U.js";import{B as o,c as b,f as i,q as n,D as r,O as s,j as l,g as t,k as e,X as E}from"./chunks/runtime-core.esm-bundler.DoiTk7Jm.js";const q=JSON.parse('{"title":"Embedding向量化入门","description":"","frontmatter":{},"headers":[],"relativePath":"column/AIFuture/基础认知/Embedding向量化入门.md","filePath":"column/AIFuture/基础认知/Embedding向量化入门.md","lastUpdated":1779160644000}'),A={name:"column/AIFuture/基础认知/Embedding向量化入门.md"};function c(m,a,u,B,_,g){const p=o("ArticleMetadata"),d=o("Mermaid");return i(),b("div",null,[a[3]||(a[3]=n("h1",{id:"embedding向量化入门",tabindex:"-1"},[t("Embedding向量化入门 "),n("a",{class:"header-anchor",href:"#embedding向量化入门","aria-label":'Permalink to "Embedding向量化入门"'},"​")],-1)),r(p),a[4]||(a[4]=s(`<p>Embedding 是把文本、图片、音频等内容转换成一组数字向量的技术。向量之间的距离可以表示语义相似度，因此它是语义搜索、推荐系统、聚类分析、RAG 知识库的基础。</p><p>OpenAI 官方文档把 Embedding 描述为把文本转换为数字，从而支持搜索、聚类等任务。</p><h2 id="一、先用一个例子理解" tabindex="-1">一、先用一个例子理解 <a class="header-anchor" href="#一、先用一个例子理解" aria-label="Permalink to &quot;一、先用一个例子理解&quot;">​</a></h2><p>有三句话：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A：我想买一台适合编程的笔记本电脑</span></span>
<span class="line"><span>B：推荐一款开发用的电脑</span></span>
<span class="line"><span>C：今晚吃什么比较好</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>关键词上，A 和 B 并不完全一样；语义上，A 和 B 很接近，C 离它们很远。</p><p>Embedding 会把它们变成向量：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>A → [0.12, -0.45, 0.87, ...]</span></span>
<span class="line"><span>B → [0.10, -0.41, 0.83, ...]</span></span>
<span class="line"><span>C → [-0.76, 0.18, 0.09, ...]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>然后通过相似度计算判断：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>相似度(A, B) &gt; 相似度(A, C)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="二、embedding-在系统里的位置" tabindex="-1">二、Embedding 在系统里的位置 <a class="header-anchor" href="#二、embedding-在系统里的位置" aria-label="Permalink to &quot;二、Embedding 在系统里的位置&quot;">​</a></h2>`,11)),(i(),l(E,null,{default:e(()=>[r(d,{id:"mermaid-30",class:"mermaid",graph:"flowchart%20TD%0A%20%20A%5B%22%E5%8E%9F%E5%A7%8B%E6%96%87%E6%9C%AC%22%5D%20--%3E%20B%5B%22%E6%B8%85%E6%B4%97%E5%92%8C%E5%88%87%E7%89%87%22%5D%0A%20%20B%20--%3E%20C%5B%22Embedding%20%E6%A8%A1%E5%9E%8B%22%5D%0A%20%20C%20--%3E%20D%5B%22%E5%90%91%E9%87%8F%22%5D%0A%20%20D%20--%3E%20E%5B%22%E5%90%91%E9%87%8F%E6%95%B0%E6%8D%AE%E5%BA%93%22%5D%0A%20%20F%5B%22%E7%94%A8%E6%88%B7%E9%97%AE%E9%A2%98%22%5D%20--%3E%20G%5B%22%E7%94%9F%E6%88%90%E6%9F%A5%E8%AF%A2%E5%90%91%E9%87%8F%22%5D%0A%20%20G%20--%3E%20H%5B%22%E7%9B%B8%E4%BC%BC%E5%BA%A6%E6%A3%80%E7%B4%A2%22%5D%0A%20%20E%20--%3E%20H%0A%20%20H%20--%3E%20I%5B%22%E8%BF%94%E5%9B%9E%E7%9B%B8%E5%85%B3%E6%96%87%E6%9C%AC%E7%89%87%E6%AE%B5%22%5D%0A"})]),fallback:e(()=>[...a[0]||(a[0]=[t(" Loading... ",-1)])]),_:1})),a[5]||(a[5]=s('<p>在 RAG 中，文档和用户问题都会被转成向量。系统通过向量距离找到语义最接近的文档片段。</p><h2 id="三、核心概念" tabindex="-1">三、核心概念 <a class="header-anchor" href="#三、核心概念" aria-label="Permalink to &quot;三、核心概念&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>解释</th><th>例子</th></tr></thead><tbody><tr><td>向量</td><td>一组数字，表示内容的语义特征</td><td><code>[0.12, -0.45, ...]</code></td></tr><tr><td>维度</td><td>向量中数字的数量</td><td>1536 维、3072 维</td></tr><tr><td>相似度</td><td>衡量两个向量是否接近</td><td>余弦相似度</td></tr><tr><td>TopK</td><td>返回最相似的前 K 条</td><td>Top5 文档片段</td></tr><tr><td>元数据</td><td>和向量一起保存的业务信息</td><td>标题、来源、权限、时间</td></tr></tbody></table><h2 id="四、常见相似度算法" tabindex="-1">四、常见相似度算法 <a class="header-anchor" href="#四、常见相似度算法" aria-label="Permalink to &quot;四、常见相似度算法&quot;">​</a></h2><h3 id="_4-1-余弦相似度" tabindex="-1">4.1 余弦相似度 <a class="header-anchor" href="#_4-1-余弦相似度" aria-label="Permalink to &quot;4.1 余弦相似度&quot;">​</a></h3><p>看两个向量方向是否接近，常用于文本语义相似度。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>cosine(A, B) 越接近 1，表示越相似</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_4-2-点积" tabindex="-1">4.2 点积 <a class="header-anchor" href="#_4-2-点积" aria-label="Permalink to &quot;4.2 点积&quot;">​</a></h3><p>常用于经过归一化的向量，计算速度快。</p><h3 id="_4-3-欧氏距离" tabindex="-1">4.3 欧氏距离 <a class="header-anchor" href="#_4-3-欧氏距离" aria-label="Permalink to &quot;4.3 欧氏距离&quot;">​</a></h3><p>看两个向量在空间中的距离，距离越短越相似。</p><p>实际项目中，不一定要自己实现这些算法，向量数据库通常已经提供。</p><h2 id="五、embedding-能做什么" tabindex="-1">五、Embedding 能做什么 <a class="header-anchor" href="#五、embedding-能做什么" aria-label="Permalink to &quot;五、Embedding 能做什么&quot;">​</a></h2><h3 id="_5-1-语义搜索" tabindex="-1">5.1 语义搜索 <a class="header-anchor" href="#_5-1-语义搜索" aria-label="Permalink to &quot;5.1 语义搜索&quot;">​</a></h3><p>用户搜索“报销规则”，系统可以找到：</p><ul><li>差旅费用审批制度</li><li>发票提交要求</li><li>补贴标准说明</li></ul><p>即使文档标题没有出现“报销规则”四个字，也可以被召回。</p><h3 id="_5-2-相似内容推荐" tabindex="-1">5.2 相似内容推荐 <a class="header-anchor" href="#_5-2-相似内容推荐" aria-label="Permalink to &quot;5.2 相似内容推荐&quot;">​</a></h3><p>文章、商品、课程、用户画像都可以向量化，然后做相似推荐。</p><h3 id="_5-3-文档去重" tabindex="-1">5.3 文档去重 <a class="header-anchor" href="#_5-3-文档去重" aria-label="Permalink to &quot;5.3 文档去重&quot;">​</a></h3><p>判断两篇文档是否高度相似，避免知识库里出现大量重复内容。</p><h3 id="_5-4-聚类分析" tabindex="-1">5.4 聚类分析 <a class="header-anchor" href="#_5-4-聚类分析" aria-label="Permalink to &quot;5.4 聚类分析&quot;">​</a></h3><p>把大量用户反馈按语义聚成几类，辅助产品分析。</p><h2 id="六、工程实践怎么做" tabindex="-1">六、工程实践怎么做 <a class="header-anchor" href="#六、工程实践怎么做" aria-label="Permalink to &quot;六、工程实践怎么做&quot;">​</a></h2><h3 id="_6-1-文档入库" tabindex="-1">6.1 文档入库 <a class="header-anchor" href="#_6-1-文档入库" aria-label="Permalink to &quot;6.1 文档入库&quot;">​</a></h3>',25)),(i(),l(E,null,{default:e(()=>[r(d,{id:"mermaid-187",class:"mermaid",graph:"sequenceDiagram%0A%20%20participant%20D%20as%20%E6%96%87%E6%A1%A3%0A%20%20participant%20C%20as%20%E6%B8%85%E6%B4%97%E5%99%A8%0A%20%20participant%20E%20as%20Embedding%E6%A8%A1%E5%9E%8B%0A%20%20participant%20V%20as%20%E5%90%91%E9%87%8F%E6%95%B0%E6%8D%AE%E5%BA%93%0A%0A%20%20D-%3E%3EC%3A%20%E6%8F%90%E5%8F%96%E6%AD%A3%E6%96%87%E3%80%81%E6%A0%87%E9%A2%98%E3%80%81%E6%9D%A5%E6%BA%90%0A%20%20C-%3E%3EC%3A%20%E6%8C%89%E6%AE%B5%E8%90%BD%E6%88%96%E6%A0%87%E9%A2%98%E5%88%87%E7%89%87%0A%20%20C-%3E%3EE%3A%20%E6%AF%8F%E4%B8%AA%E7%89%87%E6%AE%B5%E7%94%9F%E6%88%90%E5%90%91%E9%87%8F%0A%20%20E-%3E%3EV%3A%20%E5%86%99%E5%85%A5%E5%90%91%E9%87%8F%20%2B%20%E5%8E%9F%E6%96%87%20%2B%20%E5%85%83%E6%95%B0%E6%8D%AE%0A"})]),fallback:e(()=>[...a[1]||(a[1]=[t(" Loading... ",-1)])]),_:1})),a[6]||(a[6]=n("h3",{id:"_6-2-查询检索",tabindex:"-1"},[t("6.2 查询检索 "),n("a",{class:"header-anchor",href:"#_6-2-查询检索","aria-label":'Permalink to "6.2 查询检索"'},"​")],-1)),(i(),l(E,null,{default:e(()=>[r(d,{id:"mermaid-191",class:"mermaid",graph:"sequenceDiagram%0A%20%20participant%20U%20as%20%E7%94%A8%E6%88%B7%E9%97%AE%E9%A2%98%0A%20%20participant%20E%20as%20Embedding%E6%A8%A1%E5%9E%8B%0A%20%20participant%20V%20as%20%E5%90%91%E9%87%8F%E6%95%B0%E6%8D%AE%E5%BA%93%0A%20%20participant%20L%20as%20%E5%A4%A7%E6%A8%A1%E5%9E%8B%0A%0A%20%20U-%3E%3EE%3A%20%E7%94%9F%E6%88%90%E6%9F%A5%E8%AF%A2%E5%90%91%E9%87%8F%0A%20%20E-%3E%3EV%3A%20%E6%A3%80%E7%B4%A2%E7%9B%B8%E4%BC%BC%E7%89%87%E6%AE%B5%0A%20%20V-%3E%3EL%3A%20%E8%BF%94%E5%9B%9E%E4%B8%8A%E4%B8%8B%E6%96%87%0A%20%20L-%3E%3EU%3A%20%E5%9F%BA%E4%BA%8E%E4%B8%8A%E4%B8%8B%E6%96%87%E5%9B%9E%E7%AD%94%0A"})]),fallback:e(()=>[...a[2]||(a[2]=[t(" Loading... ",-1)])]),_:1})),a[7]||(a[7]=s('<h2 id="七、常见坑" tabindex="-1">七、常见坑 <a class="header-anchor" href="#七、常见坑" aria-label="Permalink to &quot;七、常见坑&quot;">​</a></h2><h3 id="_7-1-不保存原文" tabindex="-1">7.1 不保存原文 <a class="header-anchor" href="#_7-1-不保存原文" aria-label="Permalink to &quot;7.1 不保存原文&quot;">​</a></h3><p>只保存向量是不够的。向量用于检索，原文用于回答和追溯。</p><h3 id="_7-2-不保存元数据" tabindex="-1">7.2 不保存元数据 <a class="header-anchor" href="#_7-2-不保存元数据" aria-label="Permalink to &quot;7.2 不保存元数据&quot;">​</a></h3><p>至少保存：</p><ul><li>文档标题</li><li>原始链接</li><li>更新时间</li><li>所属业务</li><li>权限范围</li><li>切片序号</li></ul><h3 id="_7-3-混用不同模型" tabindex="-1">7.3 混用不同模型 <a class="header-anchor" href="#_7-3-混用不同模型" aria-label="Permalink to &quot;7.3 混用不同模型&quot;">​</a></h3><p>同一个向量库里尽量不要混用不同 Embedding 模型生成的向量，否则相似度空间不一致。</p><h3 id="_7-4-只看-topk-不看质量" tabindex="-1">7.4 只看 TopK，不看质量 <a class="header-anchor" href="#_7-4-只看-topk-不看质量" aria-label="Permalink to &quot;7.4 只看 TopK，不看质量&quot;">​</a></h3><p>TopK 返回了结果不代表结果正确。要抽样检查召回片段是否真的能回答问题。</p><h2 id="八、延伸阅读" tabindex="-1">八、延伸阅读 <a class="header-anchor" href="#八、延伸阅读" aria-label="Permalink to &quot;八、延伸阅读&quot;">​</a></h2><ul><li><a href="https://developers.openai.com/api/docs/guides/embeddings" target="_blank" rel="noreferrer">OpenAI：Vector Embeddings</a></li><li><a href="https://developers.openai.com/api/reference/resources/embeddings/methods/create" target="_blank" rel="noreferrer">OpenAI：Create Embeddings API</a></li><li><a href="https://learn.microsoft.com/en-us/azure/foundry/openai/how-to/embeddings" target="_blank" rel="noreferrer">Microsoft：Azure OpenAI Embeddings</a></li></ul><p>一句话总结：</p><blockquote><p>Embedding 是 AI 系统理解“语义相似”的基础设施。</p></blockquote>',14))])}const x=h(A,[["render",c]]);export{q as __pageData,x as default};
